SET NAMES utf8mb4;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `parentId` INT NULL;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `parent_id` INT NULL;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `payment_plan` VARCHAR(50) NULL;
ALTER TABLE `students` ADD COLUMN IF NOT EXISTS `payment_amount` DECIMAL(10,2) NULL;
ALTER TABLE `classes` ADD COLUMN IF NOT EXISTS `campus_key` VARCHAR(20) NOT NULL DEFAULT 'c1' AFTER `class_name`;
ALTER TABLE `pcm_fee_payments` MODIFY COLUMN `plan_type` ENUM('Term-wise','Half-yearly','Yearly','Additional') NOT NULL;
ALTER TABLE `pcm_fee_payments` MODIFY COLUMN `instalment_label` VARCHAR(120) NOT NULL;

